func solve(prices: Array<Int64>, strategy: Array<Int64>, k: Int64) -> Int64 {
    let n = prices.size()
    var base: Int64 = 0
    for i in 0..n {
        base += strategy[i] * prices[i]
    }

    let len_prefix = n + 1
    var prefix_prices = Array<Int64>.filled(len_prefix, 0)
    for i in 1..len_prefix {
        prefix_prices[i] = prefix_prices[i-1] + prices[i-1]
    }

    var prefix_Q = Array<Int64>.filled(len_prefix, 0)
    for i in 1..len_prefix {
        prefix_Q[i] = prefix_Q[i-1] + (strategy[i-1] * prices[i-1])
    }

    let half: Int64 = k ~/ 2
    var ans = base

    for l in 0..(n - k + 1) {
        let A: Int64 = prefix_prices[l+Int(k)] - prefix_prices[l+half]
        let B: Int64 = prefix_Q[l+Int(k)] - prefix_Q[l]
        let candidate = base + (A - B)
        if candidate > ans {
            ans = candidate
        }
    }

    return ans
}
