func solve(prices: Array<Int64>, strategy: Array<Int64>, k: Int64) -> Int64 {
    let n = prices.length;
    var prefixA = Array<Int64>(size: n+1, init: 0);
    var prefixP = Array<Int64>(size: n+1, init: 0);

    for (var i: Int = 0; i < n; i++) {
        prefixA[i+1] = prefixA[i] + strategy[i] * prices[i];
        prefixP[i+1] = prefixP[i] + prices[i];
    }

    let base = prefixA[n];
    let halfk = k / 2;
    var max_delta: Int64 = -1000000000000000000;

    if (k <= n) {
        for (var i: Int = 0; i <= n - k; i++) {
            let orig_seg = prefixA[i+k] - prefixA[i];
            let new_seg = prefixP[i+k] - prefixP[i+halfk];
            let delta = new_seg - orig_seg;
            if (delta > max_delta) {
                max_delta = delta;
            }
        }
    }

    let addition = if (max_delta > 0) { max_delta } else { 0 };
    return base + addition;
}
```

